import os
import glob

# Find and remove any FLUX 1 related files
paths_to_check = [
    "/tmp/kontext*",
    "/tmp/*kontext*",
    "/home/z/my-project/hermes-home/image_cache/*kontext*",
]

removed_files = []
for pattern in paths_to_check:
    files = glob.glob(pattern)
    for f in files:
        try:
            os.remove(f)
            removed_files.append(f)
        except:
            pass

print("Removed FLUX 1 related files:")
for f in removed_files:
    print(f"  - {f}")

if not removed_files:
    print("  No FLUX 1 files found")
"}

